import 'package:flutter/material.dart'; import '../../../core/theme/app_theme.dart'; class GreetingHeader extends StatelessWidget { final String name; const GreetingHeader({super.key, required this.name}); String get _greeting { final h = DateTime.now().hour; if (h < 12) return 'Good morning'; if (h < 17) return 'Good afternoon'; return 'Good evening'; } @override Widget build(BuildContext context) => Column(crossAxisAlignment: CrossAxisAlignment.start, children: [Text('$_greeting!', style: const TextStyle(color: AppTheme.darkSubtext, fontSize: 13)), Text(name, style: const TextStyle(color: AppTheme.darkText, fontSize: 22, fontWeight: FontWeight.w800))]); }